// // This module implements a 32-bit wide bitwise shifter that performs different types of shifts based on the input `shift` signal.
// When `shift` is 00, it outputs the input value unchanged.
// When `shift` is 01, it performs a right shift by one bit, inserting a zero in the least significant bit.
// When `shift` is 10, it performs a left shift by one bit, effectively multiplying the input by two and discarding any most significant bit.
// When `shift` is 11, it performs a left shift by two bits, inserting two zeros in the least significant bits, effectively multiplying the input by four and discarding the most significant two bits.
module top_module(
  input [31:0] in,
  input [1:0] shift,
  output reg [31:0] out
);always @(*)
  begin
    case(shift)
      2'b00: out = in;
      2'b01: out = {in[30:0], 1'b0};
      2'b10: out = {1'b0, in[31:1]};
      2'b11: out = {2'b00, in[31:2]};
    endcase
  end

endmodule

